#include <stdio.h>

int main(void) {
    double pi = 3.14159265358979;
    double e = 2.71828182845905;
    char *msg = "Hello, KernelForge!";
    printf("pi(0) = %.0f\n", pi);
    printf("pi(2) = %.2f\n", pi);
    printf("pi(6) = %.6f\n", pi);
    printf("e(4)  = %.4f\n", e);
    printf("trunc5= %.5s\n", msg);
    printf("trunc10= %.10s\n", msg);
    return 0;
}

