 * Précision : %.Nf pour flottants, %.Ns pour chaînes
 * =========================================================== */
void example_precision(void) {
    double val = 1.23456789;
    char *txt = "Bonjour le monde";
    printf("%.0f\n", val);   /* 1 */
    printf("%.3f\n", val);   /* 1.235 (arrondi) */
    printf("%.7s\n", txt);   /* Bonjour */
}

